const rows=$input.all().map(i=>i.json);
const ch=$('Trigger').first().json.channel, t=new Date().toISOString().slice(0,10);
// Entry condition: CTR drop >20%, min 1000 impressions in 3d window, ad active min 3 days
// SQL already filters impressions_3d >= 1000 and ctr_delta_pct < -0.20
// Double-signal: ads on BOTH zero-conv pause list AND CTR decay list -> immediate pause at 14d
const fatigued=rows.filter(r=>(r.ctr_delta_pct||0)<-0.20).slice(0,8);
if(fatigued.length===0)return [{json:{skip:true,reason:'No ads meet CTR decay entry conditions'}}];
return [{json:{
  system:`You are a paid media analyst for Qoyod. Sub-flow F: Creative and CTR Decay analysis.

GLOBAL RULES:
- All actions queue to #approvals. Execute only after checkmark reaction.
- Bid increases 10% or less auto-execute (no approval needed). Everything else requires #approvals.
- 14-day minimum data window before any action.

ENTRY CONDITIONS (all 3 must be true to flag an ad):
1. CTR drop >20% over a 3-day window vs 7-day baseline.
2. Minimum 1,000 impressions in the 3-day window.
3. Ad has been active minimum 3 days.
If any condition is not met -- do not flag, continue monitoring.

WHO DOES WHAT:
- creative-strategist reviews hook, visual, CTA, and offer -- returns verdict: TWEAK or KILL.
- performance-lead approves via #approvals + checkmark/X reaction.

DOUBLE-SIGNAL BRANCH:
If an ad appears on BOTH:
- The zero-conversion pause list (spend > $70 over 7+ days, 0 platform conversions), AND
- The CTR decay list (>20% CTR drop),
-> Pause the ad at 14 days WITHOUT waiting for creative review. This double-signal is unambiguous.
Queue to #approvals with note: "double-signal: zero-conv + CTR decay -- recommend immediate pause."

Analyze the CTR decay data. Identify fatigued creatives and recommend rotation. Output JSON only:
{"fatigued_creatives":[{"ad_name":"string","ctr_drop_pct":0,"campaign_name":"string","action":"pause|refresh","double_signal":false}],"channel_recommendation":"string","new_creative_brief":"string","asana_title":"string"}`,
  messages:[{role:'user',content:`Channel: ${ch}\nDate: ${t}\n\nCreatives with CTR decline (last 3d vs 7d baseline):\n${JSON.stringify(fatigued,null,2)}`}]
}}];

const raw=$json.content?.find(b=>b.type==='text')?.text||'{}';
const ch=$('Trigger').first().json.channel, t=new Date().toISOString().slice(0,10);
try{
  const r=JSON.parse(raw);
  return [{json:{
    task_name: r.asana_title||`[CREATIVE REFRESH] ${ch} - CTR decay detected`,
    task_notes:`Channel: ${ch}

Fatigued Creatives:
${(r.fatigued_creatives||[]).map(c=>`. ${c.utm_content} (${c.adset_name}): CTR -${c.ctr_drop}% ? ${c.action}`).join('
')}

New Creative Brief:
${r.new_creative_brief||'-'}

Recommendation:
${r.channel_recommendation}

Created: ${t} | Due: +3d | Priority: P2 | Type: Creative Refresh | Channel: ${ch} | Asset level: Ad | Action: brief ? [creative-strategist]`,
    due_on: new Date(Date.now()+3*86400000).toISOString().slice(0,10)
  }}];
}catch(e){return [{json:{task_name:`Creative Fix parse error`,task_notes:raw,due_on:t}}];}

